import{_ as e,o as t,c as i,ag as a}from"./chunks/framework.DXGyWiRo.js";const c=JSON.parse('{"title":"Run docker without sudo","description":"Run Docker commands without sudo","frontmatter":{"description":"Run Docker commands without sudo"},"headers":[],"relativePath":"software-engineering/containerisation/docker/run-docker-without-sudo.md","filePath":"software-engineering/containerisation/docker/run-docker-without-sudo.md"}'),o={name:"software-engineering/containerisation/docker/run-docker-without-sudo.md"};function n(r,s,h,p,d,k){return t(),i("div",null,[...s[0]||(s[0]=[a('<h1 id="run-docker-without-sudo" tabindex="-1">Run docker without sudo <a class="header-anchor" href="#run-docker-without-sudo" aria-label="Permalink to &quot;Run docker without sudo&quot;">​</a></h1><p><strong>1. Add the <code>docker</code> group if it doesn&#39;t already exist</strong></p><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$ </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">sudo</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> groupadd</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> docker</span></span></code></pre></div><p><strong>2. Add the connected user <code>$USER</code> to the docker group</strong></p><p>Optionally change the username to match your preferred user.</p><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$ </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">sudo</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> gpasswd</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> -</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">a</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> $USER </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">docker</span></span></code></pre></div><p><strong>IMPORTANT</strong>: Log out and log back in so that your group membership is re-evaluated.</p><p><strong>3. Restart the <code>docker</code> daemon</strong></p><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$ </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">sudo</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> service</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> docker</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> restart</span></span></code></pre></div><p>If you are on Ubuntu 14.04-15.10, use <code>docker.io</code> instead:</p><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$ </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">sudo</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> service</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> docker</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">io</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> restart</span></span></code></pre></div><p><strong>4. Change the context from Docker Desktop to Engine</strong></p><p>If you installed Docker Desktop first, then removed it and installed the Docker Engine, you may need to switch the Docker context with this command:</p><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$ </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">docker</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> context</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> use</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> default</span></span></code></pre></div><p>Because Docker Desktop switches context before startups and shutdowns not to interfere Docker Engine. So context might be kept incorrectly after removing Docker Desktop. A related article: <a href="https://www.howtogeek.com/devops/how-to-troubleshoot-cannot-connect-to-the-docker-daemon-errors/" target="_blank" rel="noreferrer">https://www.howtogeek.com/devops/how-to-troubleshoot-cannot-connect-to-the-docker-daemon-errors/</a></p><p><a href="https://stackoverflow.com/questions/73671461/docker-not-working-without-sudo-in-ubuntu-22-04" target="_blank" rel="noreferrer">https://stackoverflow.com/questions/73671461/docker-not-working-without-sudo-in-ubuntu-22-04</a></p>',16)])])}const u=e(o,[["render",n]]);export{c as __pageData,u as default};
